package com.projectbible.shop.maven.jpa.mysql.common.presentation;
import com.projectbible.shop.maven.jpa.mysql.common.api.ApiResponse; import org.springframework.http.HttpStatus; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.ExceptionHandler; import org.springframework.web.bind.annotation.RestControllerAdvice;
@RestControllerAdvice public class GlobalExceptionHandler { @ExceptionHandler(IllegalArgumentException.class) public ResponseEntity<ApiResponse<Void>> bad(IllegalArgumentException e) { return ResponseEntity.badRequest().body(ApiResponse.failure("BAD_REQUEST",e.getMessage(),null)); } @ExceptionHandler(Exception.class) public ResponseEntity<ApiResponse<Void>> err(Exception e) { return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(ApiResponse.failure("INTERNAL_SERVER_ERROR","Unexpected error",null)); } }
